const http = require('http');
const crypto = require('crypto');
const { URL } = require('url');

class OAuth2ResourceServer {
  constructor(config) {
    this.jwtSecret = config.jwtSecret;
    this.issuer = config.issuer;
    this.audience = config.audience;
    this.clockTolerance = config.clockTolerance || 60;
  }

  base64UrlDecode(str) {
    let base64 = str.replace(/-/g, '+').replace(/_/g, '/');
    while (base64.length % 4) {
      base64 += '=';
    }
    return Buffer.from(base64, 'base64').toString('utf8');
  }

  verifySignature(header, payload, signature) {
    const data = `${header}.${payload}`;
    const expectedSignature = crypto
      .createHmac('sha256', this.jwtSecret)
      .update(data)
      .digest('base64url');
    
    return crypto.timingSafeEqual(
      Buffer.from(signature),
      Buffer.from(expectedSignature)
    );
  }

  validateToken(token) {
    if (!token || typeof token !== 'string') {
      return { valid: false, error: 'invalid_token', description: 'Token is required' };
    }

    const parts = token.split('.');
    if (parts.length !== 3) {
      return { valid: false, error: 'invalid_token', description: 'Malformed JWT token' };
    }

    const [headerB64, payloadB64, signature] = parts;

    let header, payload;
    try {
      header = JSON.parse(this.base64UrlDecode(headerB64));
      payload = JSON.parse(this.base64UrlDecode(payloadB64));
    } catch (e) {
      return { valid: false, error: 'invalid_token', description: 'Invalid token encoding' };
    }

    if (header.alg !== 'HS256') {
      return { valid: false, error: 'invalid_token', description: 'Unsupported algorithm' };
    }

    if (!this.verifySignature(headerB64, payloadB64, signature)) {
      return { valid: false, error: 'invalid_token', description: 'Invalid signature' };
    }

    const now = Math.floor(Date.now() / 1000);

    if (payload.exp && now > payload.exp + this.clockTolerance) {
      return { valid: false, error: 'invalid_token', description: 'Token expired' };
    }

    if (payload.nbf && now < payload.nbf - this.clockTolerance) {
      return { valid: false, error: 'invalid_token', description: 'Token not yet valid' };
    }

    if (this.issuer && payload.iss !== this.issuer) {
      return { valid: false, error: 'invalid_token', description: 'Invalid issuer' };
    }

    if (this.audience) {
      const audiences = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
      if (!audiences.includes(this.audience)) {
        return { valid: false, error: 'invalid_token', description: 'Invalid audience' };
      }
    }

    return { valid: true, payload };
  }

  extractBearerToken(authHeader) {
    if (!authHeader || typeof authHeader !== 'string') {
      return null;
    }

    const parts = authHeader.split(' ');
    if (parts.length !== 2 || parts[0] !== 'Bearer') {
      return null;
    }

    return parts[1];
  }

  middleware() {
    return (req, res, next) => {
      const authHeader = req.headers['authorization'];
      const token = this.extractBearerToken(authHeader);

      if (!token) {
        res.writeHead(401, {
          'Content-Type': 'application/json',
          'WWW-Authenticate': 'Bearer realm="API", error="invalid_request", error_description="Missing or invalid Authorization header"'
        });
        res.end(JSON.stringify({
          error: 'invalid_request',
          error_description: 'Missing or invalid Authorization header'
        }));
        return;
      }

      const validation = this.validateToken(token);

      if (!validation.valid) {
        res.writeHead(401, {
          'Content-Type': 'application/json',
          'WWW-Authenticate': `Bearer realm="API", error="${validation.error}", error_description="${validation.description}"`
        });
        res.end(JSON.stringify({
          error: validation.error,
          error_description: validation.description
        }));
        return;
      }

      req.oauth = {
        token: validation.payload,
        subject: validation.payload.sub,
        scopes: validation.payload.scope ? validation.payload.scope.split(' ') : []
      };

      next();
    };
  }

  requireScope(requiredScopes) {
    return (req, res, next) => {
      if (!req.oauth || !req.oauth.scopes) {
        res.writeHead(403, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          error: 'insufficient_scope',
          error_description: 'No scopes available'
        }));
        return;
      }

      const hasRequiredScope = requiredScopes.some(scope => 
        req.oauth.scopes.includes(scope)
      );

      if (!hasRequiredScope) {
        res.writeHead(403, {
          'Content-Type': 'application/json',
          'WWW-Authenticate': `Bearer realm="API", error="insufficient_scope", scope="${requiredScopes.join(' ')}"`
        });
        res.end(JSON.stringify({
          error: 'insufficient_scope',
          error_description: 'Required scope not present',
          scope: requiredScopes.join(' ')
        }));
        return;
      }

      next();
    };
  }
}

function createServer(config) {
  const oauth = new OAuth2ResourceServer({
    jwtSecret: config.jwtSecret,
    issuer: config.issuer,
    audience: config.audience,
    clockTolerance: config.clockTolerance
  });

  const server = http.createServer((req, res) => {
    const url = new URL(req.url, `http://${req.headers.host}`);

    const next = () => {
      if (url.pathname === '/api/public') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ message: 'Public endpoint' }));
      } else if (url.pathname === '/api/protected') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          message: 'Protected resource',
          user: req.oauth.subject,
          scopes: req.oauth.scopes
        }));
      } else if (url.pathname === '/api/admin') {
        const scopeCheck = oauth.requireScope(['admin']);
        scopeCheck(req, res, () => {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({
            message: 'Admin resource',
            user: req.oauth.subject
          }));
        });
      } else {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Not found' }));
      }
    };

    if (url.pathname === '/api/public') {
      next();
    } else {
      const authMiddleware = oauth.middleware();
      authMiddleware(req, res, next);
    }
  });

  return server;
}

const config = {
  jwtSecret: process.env.JWT_SECRET || 'your-secret-key-change-in-production',
  issuer: process.env.JWT_ISSUER || 'https://auth.example.com',
  audience: process.env.JWT_AUDIENCE || 'https://api.example.com',
  clockTolerance: parseInt(process.env.CLOCK_TOLERANCE || '60', 10)
};

const server = createServer(config);

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`OAuth 2.0 Resource Server running on port ${PORT}`);
});

module.exports = { OAuth2ResourceServer, createServer };